var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그렇게, 내 얘기는 끝이야.","JPN":"……これで、私の話は終わりだ。","ENG":"... And that's how my story ends.","TWN":"……這就是我的故事。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"참 한심하지. 순간의 변덕 때문에 결국 그런 꼴이 되어 버렸다니.","JPN":"実に情けない話だ。一瞬の気の迷いで結局あの有様になってしまうなんて。","ENG":"Pretty pathetic, right? I ended up turning myself into a monster on a whim.","TWN":"很無言吧。因為一瞬間的變化，最終成了這副樣子。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"술자리 얘기로는 끝이 좋지 않군.","JPN":"バーで話すエピソードには向いてないな。","ENG":"I guess this is a bit of a buzzkill for a bar story.","TWN":"作為酒桌上的故事來說，結局不怎麼好呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"왜 마지막에 와서 거짓말을 하나?","JPN":"なぜ最後の最後に噓をつくのかね？","ENG":"Why did you lie at the end?","TWN":"妳為什麼最後要說謊？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"왜 그렇게 생각하는 거지? 확신에 찰 만한 근거라도 있나?","JPN":"なぜそう思う？　断言できる根拠でもあるのか？","ENG":"What makes you say that? How can you be so sure?","TWN":"為什麼這麼想？有什麼確鑿的證據嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 그림자로 변이했다는 건 틀림없는 사실일세.","JPN":"君がシャドウに変異したのは間違いない事実だ。","ENG":"You did indeed turn into a Shadow.","TWN":"你變異成為暗影是事實。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"식별명은 미니스트라. 확인된 것만 해도 다섯 명 이상의 카운터를 살해한 위험 개체였지.","JPN":"識別名はミニストラ。確認された記録だけでも5人以上のカウンターを殺害した危険個体だった。","ENG":"Code Name: Ministra. An extremely dangerous specimen confirmed to have slaughtered at least five Counters, possibly many more.","TWN":"識別名「潼恩」。光是目前能確認到的資訊，就是殺害過5名以上制裁者的超危險個體。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 회사 직원들은 작전 중에 자네를 격퇴하는 데 성공했다네.","JPN":"当社の社員たちは作戦中に君の撃退に成功した。","ENG":"My employees were able to defeat you during a mission.","TWN":"我們公司的職員說在作戰中有成功擊退了你。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 쉬웠다는 뜻은 아니야.","JPN":"しかし簡単な作戦ではなかった。","ENG":"That's not to say it was easy.","TWN":"我並不是想表達很容易的意思。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"몇몇 우연과 행운이 겹치지 않았다면...... 장래 유망한 소대원들을 여러 명 잃을 뻔했지.","JPN":"いくつかの偶然と幸運が重ならなければ、将来有望な小隊員を何人か失うところだった。","ENG":"Without a bit of luck and a series of coincidences... I could have lost many promising operatives that day.","TWN":"因為如果不是一些偶然和幸運的話……差點會因此失去幾個很有前途的小隊員。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_DREAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"좋아. 이제 와서 나도 못 믿겠다느니 할 생각 없어.","JPN":"いいだろう。今さら私も信じられないなんて言うつもりはない。","ENG":"Fine. I'm not going to bother arguing against any of that at this point.","TWN":"好吧，事到如今我也不會再說我不相信了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"네 말대로라면 이미 죽었어야 할 내가 여기 있다는 사실이 조금 미심쩍지만.","JPN":"お前の話どおりなら、もう死んでいるはずの私がここにいる理由が疑わしいが。","ENG":"Although I do find it suspicious that I'm not dead, if what you suggested is true.","TWN":"按你所說，我應該已經死了，卻出現這裡，確實有些匪夷所思。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래서, 내 얘기가 거짓말이라고 생각하는 이유는 뭐지?","JPN":"で、私の話が嘘だと思う理由は？","ENG":"So, why do you think I lied anyway?","TWN":"所以，你認為我說謊的理由是什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미니스트라 곁에 빈번하게 출몰하는 그림자가 하나 더 있었어.","JPN":"ミニストラのそばに頻繁に出没するシャドウがもう一体いた。","ENG":"There was one more Shadow that always appeared with Ministra.","TWN":"在迷你斯特拉身邊頻繁出沒的暗影還有一個。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"작전 기록을 확인해 보니 집에 가고 싶다고 울부짖으면서 달려들었다더군.","JPN":"作戦記録によると、家に帰りたいと泣き叫びながら襲いかかっていたそうだね。","ENG":"According to the operations logs, she cried that she wanted to go home as she attacked my employees.","TWN":"確認作戰記錄後，發現那個暗影總是在哭喊著說想回家，就會撲上來。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......집에?","JPN":"……家に？","ENG":"Home?","TWN":"……家？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"식별명은 스피라. 관리국은 미니스트라가 재조립한 그림자로 추정하고 있었지.","JPN":"識別名はスピラ。管理局はミニストラが組み直したシャドウと推定していた。","ENG":"Her codename is Spira. The Administration speculates that Ministra reassembled her into a Shadow.","TWN":"識別名「殤瞳」。管理局推測是「潼恩」重新組裝的暗影。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 확실하게 정리해 두는 편이 좋을 걸세.","JPN":"だからハッキリしておいたほうがいい。","ENG":"So I suggest you set this one thing clear, once and for all.","TWN":"所以，最好還是把這些資訊整理一下吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자신을 속이는 짓은 평생 동안 해 오지 않았나.","JPN":"自分を騙す人生はもう十分過ごしてきたじゃないか。","ENG":"You've lied to yourself all your life, after all.","TWN":"你也自欺欺人一輩子了不是嗎。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마피아 때는 싫어도 범죄자로 살았지. 어쩔 수 없이.","JPN":"マフィア時代は嫌でも犯罪者として生きてきた。やむを得ず。","ENG":"You had to lead the life of a criminal as a member of your Family. You didn't have a choice.","TWN":"做黑幫的時候，即使討厭也只能當個罪人。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네한테는 그런 세상이 전부였으니까.","JPN":"君にはそんな世界が当たり前ですべてだったから。","ENG":"That was your entire world back then.","TWN":"因為對你來說，那就是你的全部。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 다음은 냉정한 사채업자였지.","JPN":"その次は冷血な闇金業者だった。","ENG":"And then you became a cold-hearted loan shark after that.","TWN":"之後是冷靜的放貸者。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 자네는 꼭 그렇지만도 않았어.","JPN":"しかし君には人間的な面もあった。","ENG":"But you yourself weren't always so cold-hearted.","TWN":"但你也不一定是那樣的。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그림자가 되어선...... 미니스트라였지.","JPN":"そしてシャドウになってからは……ミニストラだった。","ENG":"And then when you became a Shadow... you were Ministra.","TWN":"然後成為暗影……迷你斯特拉。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자신이 아니라 누군가가 입맛대로 조립한 인격으로 바뀐 채, 이면세계를 떠돌던.","JPN":"自我はなく、誰かの好みに合わせて組み立てられた人格に変わり、裏世界をさまよっていた。","ENG":"Wandering across the Counterside with your personality reassembled by someone else to suit their desires.","TWN":"被某人按自己的喜好組裝成了全新的人格，然後在異界遊蕩。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나는...... 그 때 분명......","JPN":"私は……確かにあの時……","ENG":"I... I could have sworn...","TWN":"我……那時候明明……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런, 손님이 오셨나 보군.","JPN":"おっと、お客様が来たようだな。","ENG":"Oh, it looks like we have company.","TWN":"哎呀，看來是有客人來了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 직접 마중 나가는 편이 좋겠어.","JPN":"君が直接お出迎えに行ったほうがよさそうだ。","ENG":"You might want to go greet them yourself.","TWN":"你親自出去迎接一下吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"3종 침식체라......","JPN":"第3種侵食体か……","ENG":"Category 3, huh...","TWN":"3類侵蝕體……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"......우스꽝스러울 만큼 손쉽게 쓰러뜨렸군.","JPN":"……あっけないくらい簡単に倒したな。","ENG":"That was ridiculously easy...","TWN":"……輕而易舉就打倒了，這一切真是可笑。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"이게...... 그 녀석이 말했던 <color=#ffd34c>자매</color>인가......?","JPN":"これが……あいつが言った<color=#ffd34c>姉妹</color>の力なのか……？","ENG":"So is this... what that jerk meant by becoming a <color=#ffd34c>sister</color>?","TWN":"這……就是那傢伙說的<color=#ffd34c>姐妹</color>嗎……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"확실히 뭔가 대단한 존재라도 된 것 같은 기분이야.","JPN":"確かに我ながら何か凄い存在になったような気分だ。","ENG":"I definitely feel like I've become something special.","TWN":"確實感覺力量變強了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"수정이 몸 속으로 파고들 때는...... 그렇게나 고통스러웠는데......","JPN":"水晶が体内に食い込む時は……あんなに苦しかったのに……","ENG":"Although it was agonizing... when the crystal dug into my body...","TWN":"雖然水晶進入身體的時候……是那麼痛苦……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하아...... 윽......","JPN":"はあ……うっ……","ENG":"Ah... Ugh...","TWN":"哈啊……呃……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"정신 차려, 꼬맹이.","JPN":"しっかりしろ、ガキ。","ENG":"Get yourself together, kid.","TWN":"打起精神來，小鬼。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"주위를 둘러 봐. 이제 침식체는 더 이상 남아 있지 않아.","JPN":"周りを見ろ。もう侵食体は残っていない。","ENG":"Look around. There aren't any C.O.s left.","TWN":"看看周圍，現在已經沒有侵蝕體了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니......?","JPN":"リタお姉ちゃん……？","ENG":"Rita?","TWN":"真的是麗塔姐姐……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"......그래. 이런 모습으로 나타났으니 못 믿겠지만.","JPN":"……そうだ。こんな姿になって信じがたいと思うが。","ENG":"Yeah. Though I guess I can't blame you for not believing me, given how I look.","TWN":"……嗯。我現在這個樣子，你應該會有些難以置信吧。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"별로 어울리지는 않지?","JPN":"似合ってないだろ？","ENG":"It doesn't suit me very well, does it?","TWN":"不太合適是不是？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그 모습은...... 그림자잖아요......","JPN":"その姿は……シャドウじゃないですか……","ENG":"But you look... like a Shadow...","TWN":"那個模樣……不是暗影嗎……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 그림자가 된 거예요? 저 때문에......?","JPN":"お姉ちゃんがシャドウになったのですか？　私のせいで……？","ENG":"Have you become a Shadow, Rita? Because of... me?","TWN":"姐姐，你變成暗影了？因為我……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"경계하고 있구나. 어떤 마음인지 이해해.","JPN":"警戒しているんだな。気持ちはわかる。","ENG":"You seem to be on guard. I understand how you feel.","TWN":"你在害怕我，我理解你的心情。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"나도 너처럼 오해하고 있었어. 침식체란 것들은 전부 괴물에 불과하다고 말이야.","JPN":"私もお前みたいに誤解していた。侵食体というものは全て怪物に過ぎないと。","ENG":"I was once mistaken like you. I thought Corrupted Objects were nothing but monsters.","TWN":"一開始我也像你一樣。認為所謂侵蝕體全部都是怪物。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"하지만 그건 틀렸어.","JPN":"でもそれは間違いだ。","ENG":"But I was wrong.","TWN":"但是錯了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"그도 그럴 게...... 이렇게나 황홀한 기분인걸.","JPN":"だってそう……こんなにうっとりした気分なんだもの。","ENG":"You see... I feel fantastic right now.","TWN":"你不知道……這多讓人著迷。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"아무것도 걱정스럽지 않아. 아무것도 고통스럽지 않아.","JPN":"何の心配も要らない。何も苦しくない。","ENG":"I'm not worried about anything. No more pain and suffering.","TWN":"什麼都不用擔心，也沒有什麼痛苦。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"너에게도 가르쳐 주고 싶을 만큼.","JPN":"お前にもぜひこの気分を味わってもらいたいぐらいだ","ENG":"I wish I could share this with you.","TWN":"甚至想讓你變得跟我一樣。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"애초에 현실로 돌아가 봤자 무슨 소용이 있지?","JPN":"そもそも現実に戻って何の意味がある？","ENG":"What's the point of going back to the Normalside anyway?","TWN":"當初要回到現實世界又有什麼用呢？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"자기 잇속만 챙기려는 것들에, 배신을 일삼는 놈들, 온통 역겨운 녀석들뿐이야.","JPN":"自分の利益ばかりを考え日々裏切りを繰り返す。考えるだけで吐き気がする腐った人間だらけだ。","ENG":"The world is full of selfish jerks who'd betray you in a heartbeat to get what they want.","TWN":"不過都是一些只顧自己利益的髒東西、那些背信棄義的傢伙、令人作嘔的廢物。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"하지만 여기는 다르단다, 대시.","JPN":"しかしここは違う、ダッシュ。","ENG":"But this place is different, Dash.","TWN":"但這裡不同，黛西。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"아무도 없어. 여기에는 우리뿐이야.","JPN":"誰もいない。ここには私たちだけだ。","ENG":"There's nobody here. It's just us two.","TWN":"什麼都沒有，這裡就只有我們。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니...... 정신 차려요! 살아서 함께 여길 벗어나기로 했잖아요!","JPN":"お姉ちゃん……目を覚ましてください！　一緒に生き延びてここから脱出することにしたじゃないですか！","ENG":"Rita... Snap out of it! We were supposed to make it out of here alive! Together!","TWN":"姐姐……你清醒一下！我們不是約好了要一起活著離開這裡嗎！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저는 대표님이랑, 언니가 있는 사무소로 돌아갈 거예요! 반드시!","JPN":"私は代表とお姉ちゃんがいる事務所に戻ります！　必ず！","ENG":"I'm going to go back to the company with you and Horizon! No matter what!","TWN":"我和BOSS，要回到有姐姐在的事務所！一定！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌 파이낸스가 제 집이니까요!","JPN":"ホライズン・ファイナンスは私の家なんです！","ENG":"Horizon Finance is my home!","TWN":"因為地平線金融是我的家！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>쓰레기.</color>","JPN":"<color=#ff3636>クズ。</color>","ENG":"<color=#ff3636>You scumbag.</color>","TWN":"<color=#ff3636>垃圾。</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"꼬맹이. 거짓말은 하면 못써.","JPN":"ガキ、嘘はいけないな。","ENG":"Kid. You really shouldn't lie.","TWN":"小鬼，不能說謊。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>아무것도 못 해 주는 주제에. 입만 살아선.</color>","JPN":"<color=#ff3636>何もできないくせに、口だけは達者で。</color>","ENG":"<color=#ff3636>You useless fool. Always running that mouth of yours.</color>","TWN":"<color=#ff3636>什麼都做不了，就只會耍嘴皮子。</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"지금 나한테는...... 네 진심이 생생하게 들려.","JPN":"今の私には……お前の本音がハッキリと聞こえるんだ。","ENG":"Because right now... I can clearly hear how you really feel.","TWN":"現在我……能清清楚楚地聽到你的真心。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>범죄자. 살인마. 엄마 아빠랑 헤어지게 한 주제에. 위선자.</color>","JPN":"<color=#ff3636>犯罪者。殺人鬼。両親と別れさせたくせに。偽善者。</color>","ENG":"<color=#ff3636>Criminal. Murderer. You ripped me apart from my parents. Hypocrite.</color>","TWN":"<color=#ff3636>罪犯，殺人魔，害我和父母分開的偽善者。</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"현실로 돌아가면 그 쓰레기 부모들한테 갈 생각이지?","JPN":"現実世界に戻ったらあのクズ人間の親のところに戻るつもりだろ？","ENG":"You're thinking of going back to those scumbag parents of yours, aren't you?","TWN":"回到現實的話，你還想回到你的垃圾父母身邊吧？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아니에요, 언니! 그건 전부 환청이라고요!","JPN":"違います、お姉ちゃん！　それは幻聴です！","ENG":"No, Rita! You're hearing things in your head!","TWN":"不，姐姐！那全都是幻聽！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>이제 지긋지긋해. 왜 안 죽은 거지?</color>","JPN":"<color=#ff3636>もううんざり。なんで死ななかったんだろう？</color>","ENG":"<color=#ff3636>Ugh, I'm so sick of you. Why are you still alive?</color>","TWN":"<color=#ff3636>好煩啊，你為什麼沒死？</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>그냥 그 때 손을 놓아 버릴걸. 뻔뻔스럽게.</color>","JPN":"<color=#ff3636>あの時手を離せばよかった。図々しい。</color>","ENG":"<color=#ff3636>I should have just dropped you back then. Shameless punk.</color>","TWN":"<color=#ff3636>那時候我就應該放手，不知道廉恥。</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"그래...... 나 같은 건 안중에도 없었겠지.","JPN":"そう……最初から私のことは眼中にもなかったんだろう。","ENG":"Right... You probably never gave a darn about me.","TWN":"是啊……你應該從來沒把我放在眼裡吧。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"빚을 갚는 대로 모른 척 하고 싶은 더러운 범죄자잖아.","JPN":"借金を返した後は縁を切りたい、汚い犯罪者だから。","ENG":"You'd have nothing to do with a dirty criminal like me once you'd paid off your debt.","TWN":"一還清債務就會被你無視的骯髒罪人。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 제발......!","JPN":"お姉ちゃん、違う……！","ENG":"Rita, please!","TWN":"姐姐，求你了……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"시끄러워!!","JPN":"黙れ！！","ENG":"Shut up!","TWN":"吵死了！！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니......","JPN":"お姉ちゃん……","ENG":"Rita...","TWN":"姐姐……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"이제 지쳤어. 혼자서 마음 졸이는 건.","JPN":"もう疲れたんだ。一人で悩むのは。","ENG":"I'm tired of it now. Tired of getting anxious by myself.","TWN":"我累了，不想獨自焦慮不安了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>다시 만들면 돼.</color>","JPN":"<color=#ff3636>作り直せばいい。</color>","ENG":"<color=#ff3636>You can rebuild her.</color>","TWN":"<color=#ff3636>再做一個就行了。</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>부서졌다고 끝이 아니야.</color>","JPN":"<color=#ff3636>壊れたからって終わりじゃない。</color>","ENG":"<color=#ff3636>It's not the end just because she's broken.</color>","TWN":"<color=#ff3636>就算毀了也不代表結束。</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"......맞아. 더 이상 그럴 필요 없지.","JPN":"……そうだ。これ以上悩む必要はない。","ENG":"Right. I don't need to put up with this anymore.","TWN":"……對。沒必要再這樣了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"내 말만 잘 듣게...... <color=#ffd34c>재조립</color>하면 되는데.","JPN":"私の言うとおりに動くように……<color=#ffd34c>組み直せ</color>ばいい。","ENG":"I can make her listen only to me... by <color=#ffd34c>reassembling</color> her.","TWN":"<color=#ffd34c>重新組裝</color>……讓她只聽我的話就行了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니가...... 사람들을 해치게 놔둘 수는 없어요.","JPN":"お姉ちゃんが……人を傷つけるのを黙ってみているわけにはいきません。","ENG":"Rita... I can't let you hurt other people.","TWN":"姐姐……你如果傷害人，我不會袖手旁觀的。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"그래? 어째서?","JPN":"そう？　どうして？","ENG":"Is that right? How come?","TWN":"是嗎？你要怎樣？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"알고 있으니까요!","JPN":"知っているんです！","ENG":"Because I know!","TWN":"我知道！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"CRF 핑계를 대지만......","JPN":"CRFを言い訳にしているけど……","ENG":"You always use your CRF as an excuse...","TWN":"雖然你總是用CRF做藉口……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"사실은, 싸움 같은 건 싫어하는 사람이라는 걸요.","JPN":"実は、争いが嫌いな人ってことを。","ENG":"But I know deep down, you abhor fighting.","TWN":"其實，你是最討厭戰鬥的人。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그러니까 전 언니를 막겠어요!!","JPN":"だから、私はお姉ちゃんを止めます！！","ENG":"That's why I'll stop you!","TWN":"所以，我會阻攔姐姐的！！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니가...... 더 이상 힘들어하지 않게!","JPN":"これ以上、お姉ちゃんが……苦しまないように！","ENG":"So you won't have to... suffer anymore!","TWN":"不讓姐姐……再辛苦了！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};